findings.codeql_raw_query:
/**
 * @name Pillow ImageMath expression evaluation sources
 * @description Track untrusted data flowing into ImageMath.eval or ImageMath.eval_expr
 * @kind path-problem
 * @problem.severity error
 * @id py/pillow-imagemath-taint
 * @tags security
 *        external/cwe/cwe-094
 */

import python
import semmle.python.dataflow.new.DataFlow
import semmle.python.dataflow.new.TaintTracking
import semmle.python.dataflow.new.RemoteFlowSources
import semmle.python.ApiGraphs

module ImgMathConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(DataFlow::CallCfgNode call |
      call = API::moduleImport("PIL.ImageMath").getMember(["eval", "eval_expr"]).getACall() and
      sink = call.getArg(0)
    )
  }
}

module ImgMathFlow = TaintTracking::Global<ImgMathConfig>;
import ImgMathFlow::PathGraph

from ImgMathFlow::PathNode source, ImgMathFlow::PathNode sink
where ImgMathFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "User-controlled data reaches ImageMath expression evaluation $@.", source.getNode(), "user input"
